{"content": ""use client"
import { Header } from "@/components/header"
import { Footer } from "@/components/footer"
import { CartSidebar } from "@/components/cart-sidebar"
import { ProductModal } from "@/components/product-modal"
import { SearchAndFilters } from "@/components/search-filters"
import { CookieConsent } from "@/components/cookie-consent"
import { CartProvider, useCart } from "@/lib/cart-context"
import { useWishlist, useRecentlyViewed } from "@/lib/wishlist"
import content from "@/content/es.json"
import Link from "next/link"
import Image from "next/image"
import { useState } from "react"

const c = content as any
const cat = c.home?.productCatalog || {}
const cats = cat.categories || []
const products = cat.products || []

function TiendaContent() {
  const { addItem } = useCart()
  const { isWished, toggle } = useWishlist()
  const { add: addRecent } = useRecentlyViewed()
  const [cartOpen, setCartOpen] = useState(false)
  const [selectedProduct, setSelectedProduct] = useState<any>(null)
  const [filteredProducts, setFilteredProducts] = useState<any[] | null>(null)

  const displayProducts = filteredProducts ?? products
  const parseGs = (s: string) => parseInt(s.replace(/[^\d]/g, ""), 10) || 0

  const handleProductClick = (p: any) => {
    addRecent(p.name)
    setSelectedProduct(p)
  }

  // Group by category for display
  const groupedCategories = cats.filter((cat: string) =>
    displayProducts.some((p: any) => p.category === cat)
  )

  return (
    <>
      <Header onCartClick={() => setCartOpen(true)} />

      <section className="bg-primary py-12 text-center text-primary-foreground">
        <h1 className="text-4xl font-bold">Tienda Online</h1>
        <p className="mt-2 text-primary-foreground/80">{c.tienda?.hero?.subheadline}</p>
      </section>

      <section className="bg-surface-light py-6">
        <div className="mx-auto max-w-7xl px-4">
          <SearchAndFilters products={products} categories={cats} onFilteredProducts={setFilteredProducts} />
        </div>
      </section>

      <section className="bg-background py-16">
        <div className="mx-auto max-w-7xl px-4">
          {displayProducts.length === 0 && (
            <div className="py-20 text-center">
              <p className="text-lg text-muted-foreground">No encontramos productos con esos filtros.</p>
              <p className="text-sm text-muted-foreground mt-2">Probá con otros términos o categorías.</p>
            </div>
          )}

          {groupedCategories.length === 0 && displayProducts.length > 0 && (
            // Uncategorized view when filtering hides all categories
            <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
              {displayProducts.map((p: any, i: number) => (
                <ProductCard key={i} product={p} onClick={handleProductClick} addItem={addItem} isWished={isWished} toggleWish={toggle} parseGs={parseGs} />
              ))}
            </div>
          )}

          {groupedCategories.map((category: string) => (
            <div key={category} id={category.toLowerCase().replace(/[^a-z]/g, "")} className="mb-12">
              <div className="mb-4 flex items-center justify-between">
                <h3 className="text-xl font-bold text-primary">{category}</h3>
                <span className="text-xs text-muted-foreground">
                  {displayProducts.filter((p: any) => p.category === category).length} productos
                </span>
              </div>
              <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                {displayProducts
                  .filter((p: any) => p.category === category)
                  .slice(0, 8)
                  .map((p: any, i: number) => (
                    <ProductCard key={i} product={p} onClick={handleProductClick} addItem={addItem} isWished={isWished} toggleWish={toggle} parseGs={parseGs} />
                  ))}
              </div>
            </div>
          ))}
        </div>
      </section>

      <Footer />
      <CartSidebar open={cartOpen} onClose={() => setCartOpen(false)} />
      {selectedProduct && <ProductModal product={selectedProduct} onClose={() => setSelectedProduct(null)} />}
      <CookieConsent />
    </>
  )
}

function StockBadge({ stock }: { stock: number }) {
  if (stock === 0) return <span className="rounded-full bg-destructive/10 px-2 py-0.5 text-xs font-medium text-destructive">Agotado</span>
  if (stock <= 3) return <span className="rounded-full bg-warning/10 px-2 py-0.5 text-xs font-medium text-warning">Últimos {stock}</span>
  if (stock <= 5) return <span className="rounded-full bg-warning/5 px-2 py-0.5 text-xs font-medium text-amber-600">Quedan {stock}</span>
  return <span className="rounded-full bg-success/10 px-2 py-0.5 text-xs font-medium text-success">En stock</span>
}

function ProductCard({ product: p, onClick, addItem, isWished, toggleWish, parseGs }: any) {
  return (
    <div className="group relative overflow-hidden rounded-xl border border-border bg-surface shadow-sm transition-all hover:-translate-y-1 hover:shadow-md cursor-pointer">
