                  <p className="text-xs font-bold text-primary mt-0.5">{p.price}</p>
                </Link>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Featured Products */}
      {featuredProducts.length > 0 && (
        <section className="bg-surface-light py-16">
          <div className="mx-auto max-w-7xl px-4">
